package main

import "fmt"

func convertToBase(num int64, base int) string {
    if num == 0 {
        return "0"
    }
    var digits []rune
    for num > 0 {
        remainder := num % int64(base)
        if remainder < 10 {
            digits = append(digits, byte('0'+int(remainder)))
        } else {
            digits = append(digits, byte('A'+int(remainder-10)))
        }
        num = num / int64(base)
    }
    for i, j := 0, len(digits)-1; i < j; i, j = i+1, j-1 {
        digits[i], digits[j] = digits[j], digits[i]
    }
    return string(digits)
}

func solve(n int64) string {
    hexPart := convertToBase(n*n, 16)
    base36Part := convertToBase(n*n*n, 36)
    return hexPart + base36Part
}
